import { showPassword } from "../hooks/registration-state";
let Autorization = (props) =>{
   let p = showPassword("password");
   return(
      <div className="autorization">
         <input type="text" className = "name" placeholder="Имя пользователя"></input>
         <div className="passwordBox">
            <input type={p.type} className = {p.stateClass} placeholder="Пароль"></input>
            <svg></svg>
         </div>
         <a href="#" className="btn-type-1">Войти</a>
      </div>
   );
}
export default Autorization;
